import{c as a,Q as t,j as r,m as n}from"./chunks/framework.B5EQ7QKW.js";const o="/thalamus/main/assets/high-level-architecture.DoRDCRom.png",m=JSON.parse('{"title":"Architecture","description":"","frontmatter":{"title":"Architecture"},"headers":[],"relativePath":"concepts/architecture.md","filePath":"concepts/architecture.md","lastUpdated":1781042238000}'),i={name:"concepts/architecture.md"};function l(s,e,d,c,h,u){return t(),r("div",null,[...e[0]||(e[0]=[n('<h1 id="architecture" tabindex="-1">Architecture <a class="header-anchor" href="#architecture" aria-label="Permalink to &quot;Architecture&quot;">​</a></h1><p>Thalamus is a Kubernetes-native LLM inference stack.</p><p>It requires an AI-enabled Kubernetes cluster, for example one provided by <a href="https://gardener.cloud/" target="_blank" rel="noreferrer">Gardener</a>. The underlying hardware lifecycle is managed via metal-api and wire-api. Model weights are stored in an object store, container images in an OCI registry. Thalamus&#39; Custom Resource Definitions bundle these together as a model catalog. Operations tooling is built in via industry-standard exporters and custom extensions.</p><p><img src="'+o+'" alt="High-level architecture"></p><h2 id="inference-api" tabindex="-1">Inference API <a class="header-anchor" href="#inference-api" aria-label="Permalink to &quot;Inference API&quot;">​</a></h2><p>A single OpenAI-compatible HTTP endpoint serves all clients. Routing to the correct model and replica is handled inside the cluster by the Gateway API Inference Extension and the llm-d Endpoint Picker.</p><h2 id="kubernetes-ai-runtime" tabindex="-1">Kubernetes AI runtime <a class="header-anchor" href="#kubernetes-ai-runtime" aria-label="Permalink to &quot;Kubernetes AI runtime&quot;">​</a></h2><h3 id="gateway-api-inference-extension" tabindex="-1">Gateway API Inference Extension <a class="header-anchor" href="#gateway-api-inference-extension" aria-label="Permalink to &quot;Gateway API Inference Extension&quot;">​</a></h3><p>Model-aware HTTP routing built on the Kubernetes Gateway API. Each model is served by an <code>InferencePool</code>; requests are routed to the right pool based on the requested model.</p><h3 id="llm-d-vllm" tabindex="-1">llm-d + vLLM <a class="header-anchor" href="#llm-d-vllm" aria-label="Permalink to &quot;llm-d + vLLM&quot;">​</a></h3><p>Model servers run vLLM behind llm-d, which provides KV-cache aware load balancing across the replicas of a model.</p><h3 id="nvidia-amd-intel-gpu-operator" tabindex="-1">NVIDIA / AMD / Intel GPU Operator <a class="header-anchor" href="#nvidia-amd-intel-gpu-operator" aria-label="Permalink to &quot;NVIDIA / AMD / Intel GPU Operator&quot;">​</a></h3><p>Vendor GPU operators install drivers and expose accelerators to the cluster as schedulable resources.</p><h3 id="gardenlinux" tabindex="-1">GardenLinux <a class="header-anchor" href="#gardenlinux" aria-label="Permalink to &quot;GardenLinux&quot;">​</a></h3><p>The host operating system on the cluster nodes.</p><h3 id="metal-api-and-wire-api" tabindex="-1">metal-api and wire-api <a class="header-anchor" href="#metal-api-and-wire-api" aria-label="Permalink to &quot;metal-api and wire-api&quot;">​</a></h3><p>The bare-metal and network-fabric APIs that manage the lifecycle of the physical machines and data-center network underneath Kubernetes.</p><h2 id="platform-services" tabindex="-1">Platform services <a class="header-anchor" href="#platform-services" aria-label="Permalink to &quot;Platform services&quot;">​</a></h2><h3 id="keppel" tabindex="-1">Keppel <a class="header-anchor" href="#keppel" aria-label="Permalink to &quot;Keppel&quot;">​</a></h3><p>The OCI registry that hosts container images and the LLM catalog referenced by Thalamus&#39; Custom Resource Definitions.</p><h3 id="ceph" tabindex="-1">Ceph <a class="header-anchor" href="#ceph" aria-label="Permalink to &quot;Ceph&quot;">​</a></h3><p>The object store that holds model weights.</p><h3 id="cortex" tabindex="-1">Cortex <a class="header-anchor" href="#cortex" aria-label="Permalink to &quot;Cortex&quot;">​</a></h3><p>GPU scheduling, including gang scheduling for multi-GPU model instances.</p><h3 id="gardener" tabindex="-1">Gardener <a class="header-anchor" href="#gardener" aria-label="Permalink to &quot;Gardener&quot;">​</a></h3><p>Managed Kubernetes. Provisions and operates the AI-enabled clusters Thalamus runs on.</p><h2 id="operations" tabindex="-1">Operations <a class="header-anchor" href="#operations" aria-label="Permalink to &quot;Operations&quot;">​</a></h2><p>Metrics, logs, and traces flow through Prometheus, OpenSearch, and OpenTelemetry. Infrastructure and inference signals are surfaced through industry-standard exporters and custom extensions:</p><ul><li><strong>nvidia-smi exporter</strong>: GPU utilization, memory, temperature, power</li><li><strong>node-exporter</strong>: host-level CPU, memory, disk, network</li><li><strong>redfish exporter</strong>: hardware/BMC metrics</li><li><strong>custom exporters</strong>: inference-specific metrics</li></ul><h2 id="multi-vendor-hardware" tabindex="-1">Multi-vendor hardware <a class="header-anchor" href="#multi-vendor-hardware" aria-label="Permalink to &quot;Multi-vendor hardware&quot;">​</a></h2><p>Thalamus runs on commodity server hardware from multiple vendors with accelerators from NVIDIA, AMD, and Intel.</p><h2 id="confidential-computing" tabindex="-1">Confidential computing <a class="header-anchor" href="#confidential-computing" aria-label="Permalink to &quot;Confidential computing&quot;">​</a></h2><p>For workloads that require strong data isolation, Thalamus supports GPU confidential computing. Model weights are sealed inside an attested GPU boundary, isolated from the operator and co-tenants. Customer prompts and context are processed inside the same boundary. This enables:</p><ul><li><strong>Partner weight protection.</strong> Proprietary weights can be deployed to infrastructure the model owner does not control.</li><li><strong>Restricted-data inference.</strong> Data that cannot leave a controlled boundary can still be processed.</li></ul><h2 id="deployment-topologies" tabindex="-1">Deployment topologies <a class="header-anchor" href="#deployment-topologies" aria-label="Permalink to &quot;Deployment topologies&quot;">​</a></h2><p>The same stack runs in two topologies:</p><ul><li><strong>Datacenter.</strong> Full stack co-located in a managed Kubernetes cluster.</li><li><strong>Satellite.</strong> Air-gapped subset of the stack at the edge. The satellite carries its own OCI registry, inference gateway, model instances, and monitoring; the central datacenter retains the source-of-truth registry, object store, model catalog, and identity provider.</li></ul><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="/thalamus/main/reference/model-crd-api">Model CRD API Reference</a></li><li><a href="/thalamus/main/getting-started">Getting Started</a></li></ul>',39)])])}const g=a(i,[["render",l]]);export{m as __pageData,g as default};
